import socket
import network
import time
import json
import ubinascii
import uhashlib
import ustruct
from machine import Pin

# WiFi credentials
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# GPIO pins for IoT control
LED_PIN = 2
led = Pin(LED_PIN, Pin.OUT)

# WebSocket server
class WebSocketServer:
    def __init__(self):
        self.clients = []
        self.socket = None
        
    def start(self):
        # Connect to WiFi
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        
        while not wlan.isconnected():
            time.sleep(1)
            
        print("Connected to WiFi")
        print("IP address:", wlan.ifconfig()[0])
        
        # Create socket
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.socket.bind((wlan.ifconfig()[0], 8080))
        self.socket.listen(5)
        
        print("WebSocket server listening on port 8080")
        
        while True:
            try:
                client_socket, addr = self.socket.accept()
                print("Client connected from", addr)
                self.clients.append(client_socket)
                self.handle_client(client_socket)
            except Exception as e:
                print("Error accepting client:", e)
                continue
                
    def handle_client(self, client_socket):
        try:
            # WebSocket handshake
            request = client_socket.recv(1024).decode('utf-8')
            if not self.verify_handshake(request):
                client_socket.close()
                return
                
            # Send handshake response
            self.send_handshake_response(client_socket, request)
            
            # Main loop
            while True:
                try:
                    data = client_socket.recv(1024)
                    if not data:
                        break
                        
                    # Parse WebSocket frame
                    message = self.parse_websocket_frame(data)
                    if message:
                        self.handle_message(client_socket, message)
                        
                except Exception as e:
                    print("Error handling client message:", e)
                    break
                    
        except Exception as e:
            print("Error handling client:", e)
        finally:
            if client_socket in self.clients:
                self.clients.remove(client_socket)
            client_socket.close()
            
    def verify_handshake(self, request):
        # Basic handshake verification
        if "Upgrade: websocket" not in request:
            return False
        if "Connection: Upgrade" not in request:
            return False
        if "Sec-WebSocket-Version: 13" not in request:
            return False
        return True
        
    def send_handshake_response(self, client_socket, request):
        # Extract key from request
        key = None
        for line in request.split('\n'):
            if line.startswith('Sec-WebSocket-Key:'):
                key = line.split(':')[1].strip()
                break
                
        if not key:
            return
            
        # Generate response key
        response_key = self.generate_response_key(key)
        
        # Send handshake response
        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: " + response_key + "\r\n\r\n"
        )
        
        client_socket.send(response.encode('utf-8'))
        
    def generate_response_key(self, key):
        # WebSocket key generation
        guid = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        combined = key + guid
        sha1 = uhashlib.sha1(combined.encode('utf-8'))
        return ubinascii.b2a_base64(sha1.digest()).decode('utf-8').strip()
        
    def parse_websocket_frame(self, data):
        # Simple WebSocket frame parser
        if len(data) < 2:
            return None
            
        # Parse frame header
        first_byte = data[0]
        second_byte = data[1]
        
        # Check if it's a text frame
        if (first_byte & 0x0F) != 1:
            return None
            
        # Get payload length
        payload_len = second_byte & 0x7F
        payload_offset = 2
        
        if payload_len == 126:
            payload_len = ustruct.unpack('>H', data[2:4])[0]
            payload_offset = 4
        elif payload_len == 127:
            payload_len = ustruct.unpack('>Q', data[2:10])[0]
            payload_offset = 10
            
        # Extract payload
        payload = data[payload_offset:payload_offset + payload_len]
        return payload.decode('utf-8')
        
    def handle_message(self, client_socket, message):
        try:
            # Parse JSON command
            command = json.loads(message)
            action = command.get('action', '')
            
            # Process command
            if action == 'turn_on':
                led.on()
                response = {"status": "success", "action": "turn_on"}
            elif action == 'turn_off':
                led.off()
                response = {"status": "success", "action": "turn_off"}
            elif action == 'get_status':
                status = "on" if led.value() else "off"
                response = {"status": "success", "action": "get_status", "led_status": status}
            else:
                response = {"status": "error", "message": "Unknown action"}
                
            # Send response back to client
            self.send_message(client_socket, json.dumps(response))
            
        except Exception as e:
            print("Error processing command:", e)
            error_response = {"status": "error", "message": "Invalid JSON"}
            self.send_message(client_socket, json.dumps(error_response))
            
    def send_message(self, client_socket, message):
        # Simple WebSocket text frame
        frame = bytearray()
        frame.append(0x81)  # FIN + TEXT frame
        payload_len = len(message)
        
        if payload_len <= 125:
            frame.append(payload_len)
        elif payload_len <= 65535:
            frame.append(126)
            frame.extend(ustruct.pack('>H', payload_len))
        else:
            frame.append(127)
            frame.extend(ustruct.pack('>Q', payload_len))
            
        frame.extend(message.encode('utf-8'))
        client_socket.send(frame)

# Start server
server = WebSocketServer()
server.start()